// @ts-nocheck
import { Modal } from 'components/others';
import { useModal } from 'hooks';
import { useState, useEffect } from 'react';
import { connect } from 'react-redux';
import { Link, NavLink } from 'react-router-dom';
import { SpinnerRoundFilled } from 'spinners-react';

const navbarRoots = [
  {
    id: 1,
    url: '/cases',
    urlName: 'Cases',
    classUrl: 'text-lg font-medium leading-6 text-gray-900 hover:underline hover:underline-offset-4 select-none mx-4 border-b-2 border-white hover:border-orange-500 transition duration-300 ease-in-out'
  },
  {
    id: 2,
    url: '/services',
    urlName: 'Services',
    classUrl: 'text-lg font-medium leading-6 text-gray-900 hover:underline hover:underline-offset-4 select-none mx-4 border-b-2 border-white hover:border-orange-500 transition duration-300 ease-in-out'
  },
  {
    id: 3,
    url: '/about-us',
    urlName: 'About',
    classUrl: 'text-lg font-medium leading-6 text-gray-900 hover:underline hover:underline-offset-4 select-none mx-4 border-b-2 border-white hover:border-orange-500 transition duration-300 ease-in-out'
  },
  {
    id: 4,
    url: '/careers',
    urlName: 'Careers',
    classUrl: 'text-lg font-medium leading-6 text-gray-900 hover:underline hover:underline-offset-4 select-none mx-4 border-b-2 border-white hover:border-orange-500 transition duration-300 ease-in-out'
  },
  {
    id: 5,
    url: '/blog',
    urlName: 'Blog',
    classUrl: 'text-lg font-medium leading-6 text-gray-900 hover:underline hover:underline-offset-4 select-none mx-4 border-b-2 border-white hover:border-orange-500 transition duration-300 ease-in-out'
  },
  {
    id: 6,
    url: '/contact',
    urlName: 'Contact',
    classUrl: 'text-lg font-medium leading-6 text-gray-900 hover:underline hover:underline-offset-4 select-none mx-4 border-b-2 border-white hover:border-orange-500'
  }
];

const Navbar = () => {
  // eslint-disable-next-line no-unused-vars
  const [loading, setLoading] = useState(false);
  const { closeModal, isOpen, openModal } = useModal(false);

  useEffect(() => {
    window.onscroll = function () { scrollFunction(); };

    function scrollFunction () {
      const $navbar = document.getElementById('navbar');
      if ($navbar) {
        if (document.body.scrollTop > 100 || document.documentElement.scrollTop > 100) {
          $navbar.classList.add('shadow-navbar');
        } else {
          $navbar.classList.remove('shadow-navbar');
        }
      }
    }
  }, []);

  return (
      <nav id='navbar' className="w-full py-2 my-0 transition duration-300 ease-in-out shadow-navbarShadow fixed top-0 bg-white flex flex-col justify-center z-50">
        <ol className="border-gray-200 bg-white px-4 sm:px-6">
          <div className="-ml-4 -mt-2 flex flex-wrap items-center justify-between sm:flex-nowrap md:px-14 ">

              <li className="ml-4 mt-2">

                <Link to="/" className="text-lg font-medium leading-6 text-gray-900">
                  <img
                    className="h-8 w-auto hover:rotate-180 hover:duration-200 transition select-none"
                    src="https://tailwindui.com/img/logos/workflow-mark-indigo-500.svg"
                    alt="Workflow"
                  />
                </Link>

              </li>

              <ul className="ml-4 mt-2 flex-shrink-0 flex flex-row items-center">
                {
                  navbarRoots.map(element => <NavLink to={element.url} className={element.classUrl} key={element.id}>{element.urlName}</NavLink>)
                }

                <button
                  type="button"
                  className="ml-10 inline-flex items-center rounded-md border border-transparent bg-indigo-600 px-6 py-3 text-base font-medium text-white shadow-sm hover:bg-indigo-700 transition focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:ring-offset-2"
                  onClick={openModal}
                >
                  Login
                  <SpinnerRoundFilled enabled={true} size={25} color='#ffffff' speed={80} style={{ marginLeft: 10 }} />
                </button>
                <Modal closeModal={closeModal} isOpen={isOpen}/>
              </ul>

          </div>
        </ol>
      </nav>
  );
};

const mapStateToProps = (state) => ({

});

const mapDispatchToProps = {};

export default connect(mapStateToProps, mapDispatchToProps)(Navbar);
