// @ts-nocheck
export const observerElement = (element) => {
  const $elementToObserver = document.querySelectorAll(element);

  const options = {
    rootMargin: '50px',
    threshold: 0.5
  };

  const handlerObserver = (entries) => {
    entries.forEach((entry) => {
      if (entry.isIntersecting) {
        entry.target.classList.remove('invisibleElement');
        entry.target.classList.add('visibleElement');
      }
    });
  };

  const observer = new IntersectionObserver(handlerObserver, options);

  $elementToObserver.forEach((element) => {
    observer.observe(element);
  });
};
