import { Layout } from 'hocs/layouts';
import { Link } from 'react-router-dom';

const Error404 = () => {
  return (
    <Layout>
      <div className="min-h-screen bg-gray-900">
        <div className="py-12 sm:py-16">
          <div className="max-w-7xl mx-auto sm:px-6 lg:px-8 mt-52">
            <div className="px-4 sm:px-0">
              <h1 className="text-3xl font-bold text-slate-400 tracking-tight sm:text-4xl flex flex-colunm justify-center">
                <span className="text-red-600 mr-1">404 Error</span>:Page Not Found
              </h1>
              <p className="mt-4 text-lg text-gray-500 text-center">
                The page you are looking for does not exist.
              </p>
              <div className="mt-8 sm:flex sm:justify-center">
                <div className="mt-3 sm:mt-0 sm:ml-3">
                  <Link to="/" className="w-full flex items-center justify-center px-4 py-2 border border-transparent rounded-md shadow-sm text-base font-medium text-white bg-slate-600 hover:bg-slate-500 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 sm:w-auto">
                    Go back to home
                  </Link>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </Layout>
  );
};

export default Error404;
