// @ts-nocheck
function ServiceCard (props) {
  console.log('serviceCard: ', props.data);
  const handlerMouseEnter = () => {
    const $titleElement = document.getElementById('notice-message');
    $titleElement.classList.add('text-orange-500');
    $titleElement.classList.remove('text-gray-900');
  };

  const handlerMouseLeave = () => {
    const $titleElement = document.getElementById('notice-message');
    $titleElement.classList.remove('text-orange-500');
    $titleElement.classList.add('text-gray-900');
  };

  return (
    <>
      {
        props.data.posts.map(element => {
          return (
            <div className="element-observer invisibleElement w-full relative p-8 h-96 lg:h-[200pm] bg-white hover:-translate-y-1 transition duration-300 ease-in-out">
              <div className="w-full ">
                <img src={element.img} className='w-10 h-10' alt={element.title}/>
                <h2 className="text-xl font-semibold text-gray-900 pt-8">{element.title}</h2>
                <p className="text-lg font-regular text-gray-500 pt-4">{element.title}</p>
              </div>

              <div className="absolute bottom-0 left-0 p-8">
                <h2
                  id="notice-message"
                  onMouseEnter={handlerMouseEnter}
                  onMouseLeave={handlerMouseLeave}
                  className="items-end text-xl font-semibold text-gray-900 pt-8 cursor-pointer"
                >
                  learn More
                </h2>
              </div>
            </div>
          );
        })
      }
    </>
  );
}
export default ServiceCard;
